<script lang="ts">
  import type { SelectOption } from '@fex/components-core/select/types'; import { selectClearClassName,selectIndicatorClassName,selectInputClassName,selectPlaceholderClassName,selectSuffixClassName,selectTagClassName,selectTagOverflowClassName,selectTagRemoveClassName,selectTriggerClassName,selectValueClassName,selectValueContainerClassName } from '@fex/components-styles/select'; import { cn } from '@fex/utils'; import type { Snippet } from 'svelte'; import type { HTMLAttributes } from 'svelte/elements'; import { getContext } from 'svelte'; import ChevronRight from '../../icon/chevron-right.svelte'; import CloseIcon from '../../icon/close.svelte'; import LoadingIcon from '../../icon/loading.svelte'; import Button from '../button/button.svelte'; import PopoverTrigger from '../popover/popover-trigger.svelte'; import { selectContextKey,type SelectContext } from './context'
  interface Props extends Omit<HTMLAttributes<HTMLDivElement>,'class'|'children'|'prefix'>{class?:string|undefined;placeholder?:string|undefined;maxTagCount?:number|undefined;prefix?:Snippet|undefined;suffix?:Snippet|undefined;tag?:Snippet<[SelectOption,()=>void]>|undefined}
  let{class:className,placeholder,maxTagCount,prefix,suffix,tag,...rest}:Props=$props();const select=getContext<SelectContext>(selectContextKey);const snapshot=select.snapshot;const selected=()=>{ $snapshot.selectedValues; return select.selectedOptions() };const visible=()=>maxTagCount===undefined?selected():selected().slice(0,Math.max(0,maxTagCount))
  function keydown(event:KeyboardEvent){if(event.key==='ArrowDown'||event.key==='ArrowUp'){event.preventDefault();select.controller.open();select.controller.moveActive(event.key==='ArrowDown'?1:-1)}else if(event.key==='Home'||event.key==='End'){event.preventDefault();select.controller.moveActiveTo(event.key==='Home'?'first':'last')}else if(event.key==='Enter'){event.preventDefault();if(!select.controller.selectActive())select.controller.createTag()}else if(event.key==='Backspace'&&!$snapshot.searchValue)select.controller.removeLastSelected();else if(event.key==='Escape')select.controller.close()}
  function inputPointerdown(event:PointerEvent){if(document.activeElement===event.currentTarget)select.controller.toggleOpen();else select.controller.open()}
  function bridge<T extends Event>(handler:((event:T)=>void)|null|undefined,event:T){handler?.(event)}
</script>
<PopoverTrigger>{#snippet children(slot)}
  <div {...rest} use:slot.action data-slot="select-trigger" data-disabled={select.disabled()||undefined} data-status={select.status()} aria-invalid={select.status()==='error'||undefined} aria-expanded={$snapshot.open} class={cn(selectTriggerClassName(),className)} onclick={event=>bridge(slot.props.onclick,event as never)} onpointerenter={event=>bridge(slot.props.onpointerenter,event as never)} onpointerleave={event=>bridge(slot.props.onpointerleave,event as never)} onfocus={event=>bridge(slot.props.onfocus,event as never)} onblur={event=>bridge(slot.props.onblur,event as never)} oncontextmenu={event=>bridge(slot.props.oncontextmenu,event as never)} onkeydown={keydown}>
    {@render prefix?.()}<div class={selectValueContainerClassName}>
      {#if selected().length}{#if select.multiple()}<div class={selectValueClassName}>{#each visible() as item (item.value)}{#if tag}{@render tag(item,()=>select.removeValue(item.value))}{:else}<span class={selectTagClassName}>{item.label}<button type="button" class={selectTagRemoveClassName} onpointerdown={event=>event.preventDefault()} onclick={event=>{event.stopPropagation();select.removeValue(item.value)}}><CloseIcon/></button></span>{/if}{/each}{#if selected().length-visible().length>0}<span class={selectTagOverflowClassName}>+{selected().length-visible().length}</span>{/if}</div>{:else}<div class={selectValueClassName}>{selected()[0]?.label}</div>{/if}{:else if !$snapshot.searchValue&&!select.showSearch()}<span class={selectPlaceholderClassName}>{placeholder}</span>{/if}
      <input role="combobox" aria-expanded={$snapshot.open} aria-controls={select.listId} disabled={select.disabled()} readonly={!select.showSearch()} placeholder={select.showSearch()&&!selected().length?placeholder:undefined} value={$snapshot.searchValue} class={selectInputClassName} onfocus={()=>select.controller.open()} onpointerdown={inputPointerdown} onclick={event=>event.stopPropagation()} oninput={event=>{select.controller.setSearchValue(event.currentTarget.value);select.controller.open()}}/>
    </div><span data-slot="select-suffix" class={selectSuffixClassName}>{#if select.loading()}<LoadingIcon class="animate-spin"/>{:else if select.clearable()&&selected().length}<Button type="button" aria-label="Clear selection" class={selectClearClassName} onpointerdown={event=>event.preventDefault()} onclick={event=>{event.stopPropagation();select.controller.clear()}}><CloseIcon class="size-4"/></Button>{:else if suffix}{@render suffix()}{:else}<span data-state={$snapshot.open?'open':'closed'} class={selectIndicatorClassName}><ChevronRight class="size-4 rotate-90"/></span>{/if}</span>
  </div>
{/snippet}</PopoverTrigger>
